import { useState } from "react";

const GROQ_API_URL = "/openai/v1/chat/completions";
const GROQ_KEY = "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"; // 🔴 paste your gsk_... key here

export default function AudioCallTab({ topic, language }) {
  const [messages, setMessages] = useState([]);
  const [input,    setInput]    = useState("");
  const [loading,  setLoading]  = useState(false);

  async function sendMessage() {
    if (!input.trim()) return;
    const userMsg = { role: "user", text: input };
    setMessages((prev) => [...prev, userMsg]);
    setInput("");
    setLoading(true);

    try {
      const res = await fetch(GROQ_API_URL, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "Authorization": `Bearer ${GROQ_API_KEY}`
        },
        body: JSON.stringify({
          model: "llama-3.3-70b-versatile",
          messages: [
            {
              role: "system",
              content: `You are Aria, a friendly language tutor. 
You only help with questions about: ${topic}.
The learner is studying ${language?.name || "a language"}.
Respond in 1-3 sentences only.
Gently correct any grammar mistakes.
If asked anything outside this topic, say: "I can only help with questions about this specific lesson."`
            },
            { role: "user", content: input }
          ],
          max_tokens: 40,
          temperature: 0.8
        }),
      });

      const data = await res.json();
      const ariaMsg = { role: "aria", text: data.choices[0].message.content };
      setMessages((prev) => [...prev, ariaMsg]);
    } catch (err) {
      setMessages((prev) => [...prev, { role: "aria", text: "Sorry, something went wrong. Try again!" }]);
    }

    setLoading(false);
  }

  return (
    <div className="chat-container">
      <div className="chat-messages">
        {messages.length === 0 && (
          <p className="chat-empty">
            👋 Start talking to Aria about <strong>{topic}</strong> in {language?.name}
          </p>
        )}
        {messages.map((msg, i) => (
          <div key={i} className={`chat-bubble ${msg.role}`}>
            {msg.role === "aria" && <span className="chat-name">Aria</span>}
            <p>{msg.text}</p>
          </div>
        ))}
        {loading && (
          <div className="chat-bubble aria">
            <span className="chat-name">Aria</span>
            <p>typing...</p>
          </div>
        )}
      </div>
      <div className="chat-input-row">
        <input
          className="chat-input"
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={(e) => e.key === "Enter" && sendMessage()}
          placeholder={`Ask Aria about ${topic}...`}
        />
        <button className="chat-send" onClick={sendMessage}>➤</button>
      </div>
    </div>
  );
}
